const statsRaw = $input.first().json;
const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);

if (!Array.isArray(stats)) {
  return [{ json: { error: 'No time stats data' } }];
}

// Aggregate by day-of-week and hour
const dayHourMap = {}; // { dayOfWeek: { hour: { clicks, shows, money, revenue } } }
const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];

stats.forEach(s => {
  if (!s.date || s.hour === undefined) return;
  const date = new Date(s.date);
  const dayOfWeek = dayNames[date.getDay()];
  const hour = parseInt(s.hour);

  if (!dayHourMap[dayOfWeek]) dayHourMap[dayOfWeek] = {};
  if (!dayHourMap[dayOfWeek][hour]) {
    dayHourMap[dayOfWeek][hour] = { clicks: 0, shows: 0, money: 0, revenue: 0, count: 0 };
  }

  dayHourMap[dayOfWeek][hour].clicks += parseInt(s.clicks_count) || 0;
  dayHourMap[dayOfWeek][hour].shows += parseInt(s.shows_count) || 0;
  dayHourMap[dayOfWeek][hour].money += parseFloat(s.money) || 0;
  dayHourMap[dayOfWeek][hour].revenue += parseFloat(s.postbacks_confirmed_money) || 0;
  dayHourMap[dayOfWeek][hour].count += 1;
});

// Format summary for Claude
let summary = '';
for (const day of dayNames) {
  if (!dayHourMap[day]) continue;
  summary += `\n${day.toUpperCase()}:\n`;
  for (let h = 0; h < 24; h++) {
    const d = dayHourMap[day][h];
    if (!d) continue;
    const roi = d.money > 0 ? ((d.revenue - d.money) / d.money * 100) : 0;
    const ctr = d.shows > 0 ? (d.clicks / d.shows * 100) : 0;
    summary += `  ${String(h).padStart(2, '0')}:00 - CTR: ${ctr.toFixed(2)}%, ROI: ${roi.toFixed(0)}%, Clicks: ${d.clicks}, Spend: $${d.money.toFixed(2)}\n`;
  }
}

return [{ json: { summary, dayHourMap } }];

